const client = $('Loop Clients').item.json.fields;
const prompt = $('Loop Prompts').item.json;
const gptRaw = $('Run — ChatGPT').item.json.choices[0].message.content;
const pplxRaw = $('Run — Perplexity').item.json.choices[0].message.content;
const brand = client.name;
const comp1 = client.competitor_1 || '';
const comp2 = client.competitor_2 || '';

async function parse(raw) {
  const sys = `You are an AI response analyst. Return ONLY valid JSON with keys: brand_mentioned (bool), sentiment (positive|neutral|negative), hallucination_flag (bool), competitor_1_mentioned (bool), competitor_2_mentioned (bool). Brand: "${brand}". Comp1: "${comp1}". Comp2: "${comp2}".`;
  const res = await helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: { 'Authorization': 'Bearer ' + $env.OPENAI_API_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: 'gpt-4o-mini', temperature: 0, messages: [{ role: 'system', content: sys }, { role: 'user', content: 'Raw AI response:\n' + raw }] })
  });
  try {
    let t = res.choices[0].message.content.trim().replace(/^```json/, '').replace(/^```/, '').replace(/```$/, '');
    return JSON.parse(t);
  } catch(e) {
    return { brand_mentioned: raw.toLowerCase().includes(brand.toLowerCase()), sentiment: 'neutral', hallucination_flag: false, competitor_1_mentioned: false, competitor_2_mentioned: false };
  }
}

const [gpt, pplx] = await Promise.all([parse(gptRaw), parse(pplxRaw)]);
const d = new Date();
d.setDate(d.getDate() - d.getDay() + 1);
const weekOf = d.toISOString().split('T')[0];

return [{ json: { client_id: $('Loop Clients').item.json.id, prompt_id: prompt.id, client_name: brand, client_email: client.email, plan: client.plan, competitor_1: comp1, competitor_2: comp2, prompt_text: prompt.fields.text, week_of: weekOf, gpt, pplx, gpt_raw: gptRaw, pplx_raw: pplxRaw } }];

const allResults = $input.all().map(r => r.json.fields || r.json);
const meta = $('Parse Mentions').item.json;
const client = $('Loop Clients').item.json.fields;

const gptRows = allResults.filter(r => r.engine === 'chatgpt');
const pplxRows = allResults.filter(r => r.engine === 'perplexity');
const totalRuns = (gptRows.length + pplxRows.length) || 1;

const brandMentions = gptRows.filter(r=>r.brand_mentioned).length + pplxRows.filter(r=>r.brand_mentioned).length;
const brandSov = Math.round(brandMentions / totalRuns * 100);
const comp1Mentions = gptRows.filter(r=>r.competitor_1_mentioned).length + pplxRows.filter(r=>r.competitor_1_mentioned).length;
const comp1Sov = Math.round(comp1Mentions / totalRuns * 100);
const gap = comp1Sov - brandSov;

const mark = v => v ? "<span style='color:#4FFFB0'>&#10003;</span>" : "<span style='color:#FF4D6D'>&#10007;</span>";

const promptMap = {};
allResults.forEach(r => {
  const k = (r.prompt && r.prompt[0]) || r.prompt_id || '?';
  if (!promptMap[k]) promptMap[k] = { text: r.prompt_text || k, gpt: null, pplx: null };
  if (r.engine === 'chatgpt') promptMap[k].gpt = r.brand_mentioned;
  if (r.engine === 'perplexity') promptMap[k].pplx = r.brand_mentioned;
});

const promptRowsHtml = Object.values(promptMap).map(p =>
  `<tr style="border-top:1px solid #1E2740"><td style="padding:10px 14px;font-size:13px;color:#F0F4FF">${p.text}</td><td align="center" style="padding:10px 6px;font-size:14px">${mark(p.gpt)}</td><td align="center" style="padding:10px 6px;font-size:14px">${mark(p.pplx)}</td><td align="center" style="padding:10px 6px;font-size:13px;color:#5C6885">&mdash;</td></tr>`
).join('');

const missing = Object.values(promptMap).filter(p => p.gpt === false && p.pplx === false);
const missingHtml = missing.map(p => `<p style="margin:0 0 6px;font-size:13px;color:#8B95B0;padding:9px 14px;background:#1A2030;border-radius:7px;border-left:3px solid #FF4D6D">"${p.text}"</p>`).join('');

const hallucinations = allResults.filter(r => r.hallucination_flag);
const hallucinationBlockHtml = hallucinations.length ? `<tr><td style="padding:0 32px 20px"><table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:rgba(255,184,77,0.07);border:1px solid rgba(255,184,77,0.22);border-radius:10px"><tr><td style="padding:16px 18px"><p style="margin:0 0 4px;font-size:10px;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;color:#FFB84D">&#9888; Hallucination Flags</p><p style="margin:0 0 10px;font-size:13px;color:#8B95B0">Your brand was mentioned but the description may be inaccurate:</p>${hallucinations.map(r=>`<p style="margin:0 0 6px;font-size:13px;color:#F0F4FF">&middot; ${r.prompt_text||'?'} (${r.engine})</p>`).join('')}</td></tr></table></td></tr>` : '';

const insightText = gap > 0
  ? `${client.competitor_1 || 'Your top competitor'} appeared in ${comp1Mentions} of ${totalRuns} prompt runs — ${gap} points ahead. Focus on the ${missing.length} prompts where you're missing from both engines.`
  : `You appeared in ${brandMentions} of ${totalRuns} prompt runs. ${gap === 0 ? 'Neck and neck with ' + (client.competitor_1||'your competitor') + '.' : 'You are ahead of ' + (client.competitor_1||'your competitor') + ' by ' + Math.abs(gap) + ' points.'}`;

const d = new Date(meta.week_of);
const weekNum = Math.ceil((d - new Date(d.getFullYear(),0,1)) / 604800000);
const planFormMap = { starter: 'Np4kKB', pro: 'q4Y6xY', agency: 'QKxLg8' };
const formId = planFormMap[client.plan] || 'q4Y6xY';

const template = require('fs').readFileSync('/home/lv/codeStuff/promptpeek/templates/report_email.html', 'utf8');
const emailHtml = template
  .replace(/{{brand_name}}/g, client.name)
  .replace(/{{mention_count}}/g, brandMentions)
  .replace(/{{total_prompts}}/g, totalRuns)
  .replace(/{{week_number}}/g, weekNum)
  .replace(/{{year}}/g, d.getFullYear())
  .replace(/{{report_date}}/g, d.toLocaleDateString('en-GB',{day:'numeric',month:'long',year:'numeric'}))
  .replace(/{{engines_tracked}}/g, 'ChatGPT · Perplexity')
  .replace(/{{trend_color}}/g, '#8B95B0')
  .replace(/{{trend_label}}/g, 'first tracked week')
  .replace(/{{competitor_1_name}}/g, client.competitor_1 || '—')
  .replace(/{{competitor_1_count}}/g, comp1Mentions)
  .replace(/{{competitor_gap_pct}}/g, (gap>0?'+':'')+gap+'%')
  .replace(/{{competitor_gap_label}}/g, gap>0?(client.competitor_1||'competitor')+' is '+gap+'pts ahead':'you are ahead')
  .replace(/{{gap_color}}/g, gap>0?'#FF4D6D':'#4FFFB0')
  .replace(/{{gap_direction}}/g, gap>0?'competitor is ahead':'you are ahead')
  .replace(/{{brand_sov_pct}}/g, brandSov)
  .replace(/{{competitor_1_sov_pct}}/g, comp1Sov)
  .replace(/{{competitor_2_name}}/g, client.competitor_2 || '')
  .replace(/{{competitor_2_sov_pct}}/g, 0)
  .replace(/{{prompt_rows_html}}/g, promptRowsHtml)
  .replace(/{{missing_prompts_html}}/g, missingHtml)
  .replace(/{{hallucination_block_html}}/g, hallucinationBlockHtml)
  .replace(/{{insight_text}}/g, insightText)
  .replace(/{{plan_name}}/g, client.plan || 'Starter')
  .replace(/{{unsubscribe_url}}/g, 'https://promptscore.io/unsubscribe?email=' + encodeURIComponent(client.email));

return [{ json: { to: client.email, subject: `Prompt Score: ${client.name} appeared in ${brandMentions}/${totalRuns} AI prompts this week`, email_html: emailHtml } }];
